import { Routes, Route, NavLink, Link, useParams, Outlet }
from "react-router-dom";

function Navbar(){
    return(
        <nav>
            <Link to="/">Home</Link>
            <Link to="/about">About</Link>
            <Link to="/inventory">Inventory</Link>
            <Link to="/search">Search</Link>
        </nav>
    )
}
